<?php require_once __DIR__.'/../../config.php'; require_once __DIR__.'/../../includes/Database.php'; require_once __DIR__.'/../../includes/RedisClient.php'; require_once __DIR__.'/../../includes/Session.php'; require_once __DIR__.'/../../includes/Auth.php'; require_once __DIR__.'/../../includes/Monitor.php'; Session::start();Auth::require(); header('Content-Type: application/json; charset=utf-8'); $a=$_GET['action']??'';$db=Database::getInstance(); try{switch($a){case'summary':json_response(['success'=>true,'data'=>Monitor::getSummary()]);break;case'check':if(!Auth::validateCsrf())json_response(['error'=>'CSRF failed'],403);$sid=(int)($_POST['site_id']??0);$s=$db->fetch("SELECT * FROM `sites` WHERE id=?",[$sid]);if(!$s)json_response(['error'=>'Not found'],404);$r=Monitor::checkSite($s);Monitor::saveResult($sid,$r);json_response(['success'=>true,'data'=>$r]);break;case'check_all':if(!Auth::validateCsrf())json_response(['error'=>'CSRF failed'],403);$sites=$db->fetchAll("SELECT * FROM `sites` WHERE is_active=1");$rs=[];foreach($sites as $s){$r=Monitor::checkSite($s);Monitor::saveResult($s['id'],$r);$rs[$s['id']]=$r;}json_response(['success'=>true,'checked'=>count($sites),'data'=>$rs]);break;case'uptime':$sid=(int)($_GET['site_id']??0);json_response(['success'=>true,'data'=>Monitor::getUptimeStats($sid)]);break;case'trend':$sid=(int)($_GET['site_id']??0);$d=(int)($_GET['days']??30);json_response(['success'=>true,'data'=>Monitor::getResponseTrend($sid,$d)]);break;case'history':$sid=(int)($_GET['site_id']??0);$l=min(500,max(1,(int)($_GET['limit']??50)));json_response(['success'=>true,'data'=>$db->fetchAll("SELECT * FROM `checks` WHERE site_id=? ORDER BY checked_at DESC LIMIT ".(int)$l,[$sid])]);break;default:json_response(['success'=>true,'version'=>APP_VERSION,'endpoints'=>['summary','check','check_all','uptime','trend','history']]);}}catch(Exception $e){json_response(['success'=>false,'error'=>$e->getMessage()],500);}